import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { 
  FiUsers, FiPackage, FiTruck, FiShoppingCart, 
  FiTrendingUp, FiLogOut, FiHome, FiMenu, FiX,
  FiBarChart2, FiUserCheck
} from 'react-icons/fi';
import { useState } from 'react';

export default function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const navItems = [
    { to: '/', label: 'Dashboard', icon: FiHome, roles: ['admin', 'vendedor'], color: 'text-blue-400' },
    { to: '/usuarios', label: 'Usuarios', icon: FiUsers, roles: ['admin'], color: 'text-purple-400' },
    { to: '/productos', label: 'Productos', icon: FiPackage, roles: ['admin', 'vendedor'], color: 'text-green-400' },
    { to: '/proveedores', label: 'Proveedores', icon: FiTruck, roles: ['admin'], color: 'text-orange-400' },
    { to: '/compras/nueva', label: 'Nueva Compra', icon: FiShoppingCart, roles: ['admin'], color: 'text-yellow-400' },
    { to: '/compras', label: 'Compras', icon: FiBarChart2, roles: ['admin', 'vendedor'], color: 'text-indigo-400' },
    { to: '/ventas/nueva', label: 'Nueva Venta', icon: FiTrendingUp, roles: ['admin', 'vendedor'], color: 'text-red-400' },
    { to: '/ventas', label: 'Ventas', icon: FiUserCheck, roles: ['admin', 'vendedor'], color: 'text-pink-400' },
  ];

  const isActive = (path) => location.pathname === path;

  return (
    <>
      <nav className="bg-gradient-to-r from-slate-900 via-primary-900 to-slate-900 text-white shadow-2xl sticky top-0 z-50 backdrop-blur-sm">
        <div className="container mx-auto px-4">
          <div className="flex justify-between items-center py-4">
            {/* Logo */}
            <Link to="/" className="flex items-center space-x-3 group">
              <div className="text-3xl transform group-hover:scale-110 transition-transform duration-300">
                🚀
              </div>
              <div>
                <div className="text-xl font-bold bg-gradient-to-r from-blue-400 to-purple-400 bg-clip-text text-transparent">
                  Sistema Pro
                </div>
                <div className="text-xs text-gray-400">Gestión Empresarial</div>
              </div>
            </Link>
            
            {/* Desktop Menu */}
            <div className="hidden lg:flex items-center space-x-1">
              {navItems.map((item) => {
                if (!item.roles.includes(user?.rol)) return null;
                const Icon = item.icon;
                const active = isActive(item.to);
                return (
                  <Link
                    key={item.to}
                    to={item.to}
                    className={`flex items-center space-x-2 px-4 py-2 rounded-xl transition-all duration-300
                      ${active 
                        ? 'bg-white/20 text-white shadow-lg transform scale-105' 
                        : 'hover:bg-white/10 hover:scale-105'
                      }`}
                  >
                    <Icon className={`text-lg ${active ? item.color : 'text-gray-300'}`} />
                    <span className="text-sm font-medium">{item.label}</span>
                    {active && (
                      <div className="absolute bottom-0 left-1/2 transform -translate-x-1/2 w-8 h-0.5 bg-gradient-to-r from-blue-400 to-purple-400 rounded-full"></div>
                    )}
                  </Link>
                );
              })}
              
              {/* User Profile */}
              <div className="ml-6 pl-6 border-l border-white/20 flex items-center space-x-4">
                <div className="flex items-center space-x-3">
                  <div className="w-10 h-10 rounded-full bg-gradient-to-r from-blue-500 to-purple-500 flex items-center justify-center shadow-lg">
                    <span className="text-lg font-bold">{user?.nombre?.charAt(0)}</span>
                  </div>
                  <div className="hidden xl:block">
                    <div className="text-sm font-semibold">{user?.nombre}</div>
                    <div className="text-xs text-gray-300 capitalize">{user?.rol}</div>
                  </div>
                </div>
                <button
                  onClick={handleLogout}
                  className="flex items-center space-x-2 px-4 py-2 rounded-xl bg-red-500/20 hover:bg-red-500/30 transition-all duration-300 hover:scale-105"
                >
                  <FiLogOut className="text-red-400" />
                  <span className="hidden xl:inline">Salir</span>
                </button>
              </div>
            </div>
            
            {/* Mobile Menu Button */}
            <button
              onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
              className="lg:hidden p-2 rounded-xl hover:bg-white/10 transition-all"
            >
              {mobileMenuOpen ? <FiX className="text-2xl" /> : <FiMenu className="text-2xl" />}
            </button>
          </div>
        </div>
      </nav>
      
      {/* Mobile Menu */}
      {mobileMenuOpen && (
        <div className="lg:hidden fixed inset-0 z-40 bg-slate-900/95 backdrop-blur-md animate-slide-down">
          <div className="flex flex-col p-6 space-y-3 mt-16">
            {navItems.map((item) => {
              if (!item.roles.includes(user?.rol)) return null;
              const Icon = item.icon;
              return (
                <Link
                  key={item.to}
                  to={item.to}
                  onClick={() => setMobileMenuOpen(false)}
                  className="flex items-center space-x-3 px-4 py-3 rounded-xl hover:bg-white/10 transition-all"
                >
                  <Icon className="text-xl text-gray-300" />
                  <span className="text-white">{item.label}</span>
                </Link>
              );
            })}
            <button
              onClick={handleLogout}
              className="flex items-center space-x-3 px-4 py-3 rounded-xl bg-red-500/20 hover:bg-red-500/30 transition-all mt-4"
            >
              <FiLogOut className="text-xl text-red-400" />
              <span className="text-white">Cerrar Sesión</span>
            </button>
          </div>
        </div>
      )}
    </>
  );
}
